--liquibase formatted sql

--changeset scpeterson:038-add-section-g-gravesites splitStatements:false
WITH trinity AS (
  SELECT id, facility_id
  FROM cemeteries
  WHERE facility_id = '1'
     OR name = 'Trinity Lutheran Church Cemetery'
  ORDER BY facility_id = '1' DESC, name
  LIMIT 1
),
section_g AS (
  SELECT sections.section_id AS section_uuid, sections.name AS section_name
  FROM sections
  JOIN trinity ON trinity.id = sections.cemetery_id
  WHERE sections.name = 'G'
    AND sections.deleted_at IS NULL
  LIMIT 1
),
source_gravesites(gravesite_id, grave_id, name, wkt) AS (
