INSERT INTO gravesites (
  cemetery_id,
  section_uuid,
  lot_uuid,
  name,
  facility_id,
  section_id,
  block_id,
  lot_id,
  grave_id,
  gravesite_id,
  status,
  width_feet,
  length_feet,
  geometry,
  updated_at
)
SELECT
  trinity.id,
  section_g.section_uuid,
  NULL::uuid,
  source_gravesites.name,
  trinity.facility_id,
  section_g.section_name,
  NULL::varchar(5),
  NULL::varchar(5),
  source_gravesites.grave_id,
  source_gravesites.gravesite_id,
  'unknown',
  4.00,
  8.00,
  ST_SetSRID(ST_GeomFromText(source_gravesites.wkt), 4326)::geometry(MultiPolygon, 4326),
  now()
FROM source_gravesites
CROSS JOIN trinity
CROSS JOIN section_g
ON CONFLICT (cemetery_id, gravesite_id) DO UPDATE SET
  section_uuid = EXCLUDED.section_uuid,
  lot_uuid = NULL,
  name = EXCLUDED.name,
  facility_id = EXCLUDED.facility_id,
  section_id = EXCLUDED.section_id,
  block_id = NULL,
  lot_id = NULL,
  grave_id = EXCLUDED.grave_id,
  status = EXCLUDED.status,
  width_feet = EXCLUDED.width_feet,
  length_feet = EXCLUDED.length_feet,
  geometry = EXCLUDED.geometry,
  deleted_at = NULL,
  deleted_by = NULL,
  delete_reason = NULL,
  updated_at = now();

--rollback DELETE FROM gravesites WHERE section_id = 'G' AND gravesite_id BETWEEN 'G-001' AND 'G-094' AND NOT EXISTS (SELECT 1 FROM burials WHERE burials.gravesite_uuid = gravesites.id) AND NOT EXISTS (SELECT 1 FROM owners WHERE owners.gravesite_uuid = gravesites.id) AND NOT EXISTS (SELECT 1 FROM headstones WHERE headstones.gravesite_uuid = gravesites.id) AND NOT EXISTS (SELECT 1 FROM headstone_gravesites WHERE headstone_gravesites.gravesite_uuid = gravesites.id) AND NOT EXISTS (SELECT 1 FROM gravesite_media_assets WHERE gravesite_media_assets.gravesite_uuid = gravesites.id) AND NOT EXISTS (SELECT 1 FROM north_hills_ocr_entry_gravesite_links WHERE north_hills_ocr_entry_gravesite_links.gravesite_uuid = gravesites.id);
